// Example 17: Functions that branch on mock return values.
// Tests dynamic mock discovery — the concolic explorer should generate varied
// mock return values per iteration to discover all branches gated by external
// dependency behavior.
//
// Each function imports an external module (fs) so the analyzer detects
// external dependencies. The branches are controlled by mock return values,
// not by direct parameters alone.

import * as fs from "fs";

// ── HTTP-like status branching ─────────────────────────────────────────
//
// Simulates a function that reads a file and branches on its content,
// which acts as a "status" from an external source.
//
// EXPECTED BRANCHES (4):
//   1. status === "200"   → "ok"
//   2. status === "404"   → "not-found"
//   3. status === "500"   → "server-error"
//   4. default            → "unknown:<status>"
//
// MOCKS: fs.readFileSync returns the status string.
// Dynamic mocking should vary the readFileSync return value to discover all 4 branches.
export function classifyStatus(configPath: string): string {
    const status = fs.readFileSync(configPath, "utf-8").trim();

    if (status === "200") {
        return "ok";
    }
    if (status === "404") {
        return "not-found";
    }
    if (status === "500") {
        return "server-error";
    }
    return `unknown:${status}`;
}

// ── Result/Error branching ─────────────────────────────────────────────
//
// Reads a config file; branches on whether the read succeeds or throws,
// and on the content when it succeeds.
//
// EXPECTED BRANCHES (3):
//   1. fs.existsSync returns false  → "missing"
//   2. file exists, content empty   → "empty-config"
//   3. file exists, content present → "loaded:<length>"
//
// MOCKS: fs.existsSync → true/false, fs.readFileSync → string content.
// Dynamic mocking should vary both mock return values.
export function loadOrDefault(filePath: string): string {
    if (!fs.existsSync(filePath)) {
        return "missing";
    }

    const content = fs.readFileSync(filePath, "utf-8");
    if (content.length === 0) {
        return "empty-config";
    }

    return `loaded:${content.length}`;
}

// ── Loop with mock-per-iteration ───────────────────────────────────────
//
// Reads multiple config files in a loop. Each iteration calls readFileSync,
// and the branch depends on whether the content starts with "#".
//
// EXPECTED BRANCHES (3):
//   1. all files start with "#"    → "all-comments"
//   2. no files start with "#"     → "no-comments"
//   3. mixed                       → "mixed"
//
// MOCKS: fs.readFileSync returns different content per call.
// Dynamic mocking cycles through return_values, so varied values per call
// produce different branch outcomes.
export function classifyConfigs(paths: string[]): string {
    if (paths.length === 0) {
        return "no-comments";
    }

    let commentCount = 0;
    for (const p of paths) {
        const content = fs.readFileSync(p, "utf-8");
        if (content.startsWith("#")) {
            commentCount++;
        }
    }

    if (commentCount === paths.length) {
        return "all-comments";
    }
    if (commentCount === 0) {
        return "no-comments";
    }
    return "mixed";
}

