        max_iterations: 10,
        seed: Some(42),
        mocks: vec![],
        setup_file: Some(setup_file_str),
        setup_level: SetupLevel::Function,
        value_sources: vec![],
        capabilities: capabilities_with_setup(),
        user_seeds: vec![],
        candidate_inputs: vec![],
        pool_seeds: vec![],
