/// Analyze a function's external dependencies and build auto-mocks + mock params
/// for dynamic per-iteration mock generation.
async fn setup_mocks_for_function(
    frontend: &mut Frontend,
    file: &str,
    function_name: &str,
) -> (
    shatter_core::protocol::FunctionAnalysis,
    Vec<shatter_core::protocol::MockConfig>,
    Vec<shatter_core::auto_mock::MockParam>,
) {
    let analysis = analyze_function(frontend, file, function_name).await;

    let auto_mocks = shatter_core::auto_mock::generate_auto_mocks(
        &analysis.dependencies,
        None,
        &std::collections::HashMap::new(),
        &[],
    );

    let mock_params = shatter_core::auto_mock::build_mock_params(
        &analysis.dependencies,
        &auto_mocks,
    );

    (analysis, auto_mocks, mock_params)
}

/// Test that dynamic mock discovery finds all branches gated by mock return values
/// in classifyStatus (HTTP-like status branching).
///
/// classifyStatus(configPath) reads a file via fs.readFileSync and branches on content:
///   1. "200"     → "ok"
///   2. "404"     → "not-found"
///   3. "500"     → "server-error"
///   4. default   → "unknown:<status>"
///
/// Dynamic mocking should vary readFileSync return values across iterations
/// to discover all 4 branches.
#[tokio::test]
async fn concolic_mock_status_branches_discovered() {
    let file = examples_dir().join("17-mock-branches.ts");
    let file_str = file.to_string_lossy().to_string();

    let mut frontend = spawn_ts_frontend().await;

    let (analysis, auto_mocks, mock_params) =
        setup_mocks_for_function(&mut frontend, &file_str, "classifyStatus").await;

    assert!(
        !analysis.dependencies.is_empty(),
        "classifyStatus should have external dependencies (fs)"
    );

    instrument_function_with_mocks(&mut frontend, &file_str, "classifyStatus", auto_mocks.clone())
        .await;

    let config = ExploreConfig {
        max_iterations: 30,
        max_executions: 200,
        plateau_threshold: 20,
        mocks: auto_mocks,
        mock_params,
        ..Default::default()
    };

    let seed_inputs = vec![vec![serde_json::json!("/tmp/config.txt")]];

    let result = orchestrator::explore(
        &mut frontend,
        "classifyStatus",
        seed_inputs,
        vec![],
        &analysis.params,
        &config,
        None,
    )
    .await
    .expect("concolic exploration failed");

    let return_values = return_value_set(&result);

    eprintln!("  [str-3ky9.8/status] unique_paths: {}", result.unique_paths);
    eprintln!("  [str-3ky9.8/status] return_values: {return_values:?}");

    // Dynamic mocking should discover at least 3 of the 4 status branches.
    assert!(
        result.unique_paths >= 3,
        "should have at least 3 unique paths from mock-gated branches; got {}. \
         return_values: {return_values:?}",
        result.unique_paths
    );

    assert!(
        return_values.contains("\"ok\""),
        "should discover 'ok' branch (status 200); found: {return_values:?}"
    );

    assert!(
        return_values.contains("\"not-found\""),
        "should discover 'not-found' branch (status 404); found: {return_values:?}"
    );

    frontend.shutdown().await.expect("frontend shutdown failed");
}

/// Test that dynamic mock discovery explores both success and failure paths
/// in loadOrDefault (Result-like branching).
///
/// loadOrDefault(filePath) branches on:
///   1. fs.existsSync returns false  → "missing"
///   2. file exists, content empty   → "empty-config"
///   3. file exists, content present → "loaded:<length>"
///
/// Dynamic mocking should vary existsSync and readFileSync return values.
#[tokio::test]
async fn concolic_mock_result_branches_discovered() {
    let file = examples_dir().join("17-mock-branches.ts");
    let file_str = file.to_string_lossy().to_string();

    let mut frontend = spawn_ts_frontend().await;

    let (analysis, auto_mocks, mock_params) =
        setup_mocks_for_function(&mut frontend, &file_str, "loadOrDefault").await;

    assert!(
        !analysis.dependencies.is_empty(),
        "loadOrDefault should have external dependencies (fs)"
    );

    instrument_function_with_mocks(&mut frontend, &file_str, "loadOrDefault", auto_mocks.clone())
        .await;

    let config = ExploreConfig {
        max_iterations: 30,
        max_executions: 200,
        plateau_threshold: 20,
        mocks: auto_mocks,
        mock_params,
        ..Default::default()
    };

    let seed_inputs = vec![vec![serde_json::json!("/tmp/config.txt")]];

    let result = orchestrator::explore(
        &mut frontend,
        "loadOrDefault",
        seed_inputs,
        vec![],
        &analysis.params,
        &config,
        None,
    )
    .await
    .expect("concolic exploration failed");

    let return_values = return_value_set(&result);

    eprintln!("  [str-3ky9.8/result] unique_paths: {}", result.unique_paths);
    eprintln!("  [str-3ky9.8/result] return_values: {return_values:?}");

    // Should discover at least 2 of 3 branches (missing + one success variant).
    assert!(
        result.unique_paths >= 2,
        "should have at least 2 unique paths from mock-gated Ok/Err branches; got {}. \
         return_values: {return_values:?}",
        result.unique_paths
    );

    // At minimum, dynamic mocking should discover the "missing" path
    // (existsSync returns false) and at least one success path.
    let has_missing = return_values.iter().any(|v| v.contains("missing"));
    let has_success = return_values
        .iter()
        .any(|v| v.contains("loaded:") || v.contains("empty-config"));
    assert!(
        has_missing || has_success,
        "should discover at least the 'missing' or a success path; found: {return_values:?}"
    );

    frontend.shutdown().await.expect("frontend shutdown failed");
}

/// Test that dynamic mock discovery handles loop-based mock calls
/// in classifyConfigs (per-iteration mock return values).
///
/// classifyConfigs(paths) loops over paths, calling readFileSync per element:
///   1. all files start with "#"    → "all-comments"
///   2. no files start with "#"     → "no-comments"
///   3. mixed                       → "mixed"
///
/// Dynamic mocking cycles through return_values, so varied values per call
/// produce different branch outcomes. Empty paths array → "no-comments".
#[tokio::test]
async fn concolic_mock_loop_branches_discovered() {
    let file = examples_dir().join("17-mock-branches.ts");
    let file_str = file.to_string_lossy().to_string();

    let mut frontend = spawn_ts_frontend().await;

    let (analysis, auto_mocks, mock_params) =
        setup_mocks_for_function(&mut frontend, &file_str, "classifyConfigs").await;

    instrument_function_with_mocks(
        &mut frontend,
        &file_str,
        "classifyConfigs",
        auto_mocks.clone(),
    )
    .await;

    let config = ExploreConfig {
        max_iterations: 40,
        max_executions: 300,
        plateau_threshold: 25,
        mocks: auto_mocks,
        mock_params,
        ..Default::default()
    };

    // Seed with arrays of 2-3 paths so the loop body executes multiple times,
    // giving mock cycling a chance to produce varied per-call return values.
    let seed_inputs = vec![
        vec![serde_json::json!(["a.txt", "b.txt"])],
        vec![serde_json::json!(["x.txt", "y.txt", "z.txt"])],
        vec![serde_json::json!([])],
    ];

    let result = orchestrator::explore(
        &mut frontend,
        "classifyConfigs",
        seed_inputs,
        vec![],
        &analysis.params,
        &config,
        None,
    )
    .await
    .expect("concolic exploration failed");

    let return_values = return_value_set(&result);

    eprintln!("  [str-3ky9.8/loop] unique_paths: {}", result.unique_paths);
    eprintln!("  [str-3ky9.8/loop] return_values: {return_values:?}");

    // With varied mock returns per iteration, should discover at least 2 of 3 branches.
    assert!(
        result.unique_paths >= 2,
        "should have at least 2 unique paths from loop mock cycling; got {}. \
         return_values: {return_values:?}",
        result.unique_paths
    );

    // Verify at least one comment-related branch is discovered.
    let has_comment_branch = return_values
        .iter()
        .any(|v| v.contains("comments") || v.contains("mixed"));
    assert!(
        has_comment_branch,
        "should discover at least one comment-related branch; found: {return_values:?}"
    );

    frontend.shutdown().await.expect("frontend shutdown failed");
}

