async fn setup_mocks_for_function(
    frontend: &mut Frontend,
    file: &str,
    function_name: &str,
) -> (
    shatter_core::protocol::FunctionAnalysis,
    Vec<shatter_core::protocol::MockConfig>,
    Vec<shatter_core::auto_mock::MockParam>,
) {
    let analysis = analyze_function(frontend, file, function_name).await;

    let auto_mocks = shatter_core::auto_mock::generate_auto_mocks(
        &analysis.dependencies,
        None,
        &std::collections::HashMap::new(),
        &[],
    );

    let mock_params = shatter_core::auto_mock::build_mock_params(
        &analysis.dependencies,
        &auto_mocks,
    );

    (analysis, auto_mocks, mock_params)
}

