// Example 17: Functions that branch on mock return values.
// Tests dynamic mock discovery — the concolic explorer should generate varied
// mock return values per iteration to discover all branches gated by external
// dependency behavior.
//
// Uses named imports (not namespace import) so the instrumentor can rewrite
// individual symbols for mock interception.
//
// Branch conditions use prefix/length/truthiness checks (not exact string
// equality) so that random mock value generation can discover branches
// without needing to guess specific magic strings.

import { readFileSync, existsSync } from "fs";

// ── Status-code branching via prefix ────────────────────────────────────
//
// Reads a config file and branches on the first character of its content.
// Each prefix maps to a status category.
//
// EXPECTED BRANCHES (4):
//   1. starts with "2"   → "success"
//   2. starts with "4"   → "client-error"
//   3. starts with "5"   → "server-error"
//   4. default            → "unknown"
//
// MOCKS: readFileSync returns a status string.
// Dynamic mocking with random strings will eventually produce strings
// starting with "2", "4", "5", or other characters.
export function classifyStatus(configPath: string): string {
    const status = (readFileSync(configPath, "utf-8") as string).trim();

    if (status.startsWith("2")) {
        return "success";
    }
    if (status.startsWith("4")) {
        return "client-error";
    }
    if (status.startsWith("5")) {
        return "server-error";
    }
    return "unknown";
}

// ── Result/Error branching ─────────────────────────────────────────────
//
// Reads a config file; branches on whether the file exists and on the
// length of the content when it does.
//
// EXPECTED BRANCHES (3):
//   1. existsSync returns false        → "missing"
//   2. file exists, content length < 5 → "short-config"
//   3. file exists, content length >= 5 → "loaded"
//
// MOCKS: existsSync → boolean, readFileSync → string.
// Dynamic mocking should vary boolean returns and string lengths.
export function loadOrDefault(filePath: string): string {
    if (!existsSync(filePath)) {
        return "missing";
    }

    const content = readFileSync(filePath, "utf-8") as string;
    if (content.length < 5) {
