    let result = orchestrator::explore(
        &mut frontend,
        "classifyNumber",
        seed_inputs,
        vec![],
        &analysis.params,
        &config,
        Some(setup_ctx),
    )
    .await
    .expect("orchestrator explore with setup context failed");

    assert!(
        result.unique_paths >= 2,
        "orchestrator with setup context should discover at least 2 paths; got {}",
        result.unique_paths
    );

