    let mut frontend = spawn_ts_frontend().await;

    let analysis = analyze_function(&mut frontend, &file_str, "loadOrDefault").await;

    let mocks = vec![
        existssync_mock(&[true, false, true]),
        readfilesync_mock(&["some content", "", "hello"]),
    ];
    let mock_params = vec![
        fs_mock_param("fs:existsSync", TypeInfo::Bool, 1),
        fs_mock_param("fs:readFileSync", TypeInfo::Str, 1),
    ];

    instrument_function_with_mocks(&mut frontend, &file_str, "loadOrDefault", mocks.clone())
        .await;

    let config = ExploreConfig {
        max_iterations: 30,
        max_executions: 200,
        plateau_threshold: 20,
        mocks: mocks.clone(),
        mock_params,
        ..Default::default()
    };

    let seed_inputs = vec![vec![serde_json::json!("config.txt")]];

    let result = orchestrator::explore(
        &mut frontend,
        "loadOrDefault",
        seed_inputs,
        vec![],
        &analysis.params,
        &config,
