// ── Status-code branching via first character ───────────────────────────
//
// Reads a config file and branches on the first character of its content.
// Each character maps to a status category.
//
// EXPECTED BRANCHES (4):
//   1. first char is a digit (0-9) → "numeric"
//   2. first char is uppercase     → "uppercase"
//   3. empty string                → "empty"
//   4. default (lowercase/symbol)  → "other"
//
// MOCKS: readFileSync returns a status string.
// Dynamic mocking with random strings produces diverse first characters,
// giving good coverage of the branches.
export function classifyStatus(configPath: string): string {
    const status = (readFileSync(configPath, "utf-8") as string).trim();

    if (status.length === 0) {
        return "empty";
    }

    const first = status.charCodeAt(0);
    if (first >= 48 && first <= 57) {
        return "numeric";
    }
    if (first >= 65 && first <= 90) {
        return "uppercase";
    }
    return "other";
}

