        .expect("setup for auth.ts failed");

    let ctx_auth = match response_auth.result {
        ResponseResult::Setup { setup_context } => {
            assert_eq!(
                setup_context.get("fileScope").and_then(|v| v.as_str()),
                Some("auth.ts"),
                "auth.ts setup should return its own scope"
